    try {
        if (typeof process !== 'undefined' && process.env && process.env[key]) return process.env[key];
        // @ts-ignore
        if (typeof import.meta !== 'undefined' && import.meta.env && import.meta.env[key]) return import.meta.env[key];
    } catch (e) {}
    return undefined;
