const isHardcodedFilled = HARDCODED_CONFIG.apiKey && !HARDCODED_CONFIG.apiKey.includes("PASTE_YOUR");
const isEnvFilled = !!envConfig.apiKey;

// העדפה: אם מילאת ידנית, זה יקבל עדיפות כדי לפתור את הבעיה.
