    source: isHardcodedFilled ? 'Hardcoded File (Manual)' : (isEnvFilled ? 'Vercel Env Vars' : 'None'),
};

try {
    if (!firebaseConfig) {
        console.warn("[Firebase Init] No configuration found. Please fill HARDCODED_CONFIG in lib/firebase.ts");
        initializationError = "Missing Configuration";
    } else {
        // Initialize
        app = !getApps().length ? initializeApp(firebaseConfig) : getApp();
        db = getFirestore(app);
        storage = getStorage(app);
        auth = getAuth(app);
        console.log('[Firebase Init] Success using:', debugEnv.source);
    }
} catch (error: any) {
    console.error("[Firebase Init] Exception:", error);
    initializationError = error.message || "Unknown initialization error";
}

