                     if (text.includes("API_KEY is missing")) setServerStatus("MISSING API_KEY");
                     else setServerStatus("SERVER ERROR");
                } else if (res.status === 400) setServerStatus("OK");
                else setServerStatus("UNKNOWN");
            })
