const HomePage: React.FC = () => {
  const [propertyDetails, setPropertyDetails] = useState<PropertyDetails | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isClient, setIsClient] = useState(false);
  const [showSystemCheck, setShowSystemCheck] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [currentView, setCurrentView] = useState<'create' | 'dashboard' | 'admin'>('create');
  const router = useAppRouter();

  useEffect(() => {
    setIsClient(true);
    if (initializationError || !auth) return;
    const unsubscribe = onAuthStateChanged(auth, async (currentUser: User | null) => {
      setUser(currentUser);
      if (currentUser) {
        const userEmail = currentUser.email?.toLowerCase() || '';
        const isUserAdmin = ADMIN_EMAILS.some(email => email.toLowerCase() === userEmail);
        setIsAdmin(isUserAdmin);
        try {
            if (db) {
                const userRef = doc(db, 'users', currentUser.uid);
                await setDoc(userRef, {
                    uid: currentUser.uid,
                    email: currentUser.email,
                    displayName: currentUser.displayName,
                    photoURL: currentUser.photoURL,
                    lastLogin: Date.now(),
                    role: isUserAdmin ? 'admin' : 'user'
                } as UserProfile, { merge: true });
            }
        } catch (e) { console.error("Error syncing user profile:", e); }
      } else {
        setIsAdmin(false);
        setCurrentView('create');
      }
    });
    return () => unsubscribe();
  }, []);

  const handleFormSubmit = async (formData: PropertyFormData) => {
    if (!user) { alert("עליך להתחבר למערכת כדי ליצור דף נחיתה."); return; }
    if (formData.images.length === 0) { alert('אנא העלה לפחות תמונה אחת.'); return; }
    setIsLoading(true);
    try {
      const response = await fetch('/api/generate-content', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ originalDescription: formData.description, address: formData.address }),
      });
      if (!response.ok) {
          const errorText = await response.text();
          throw new Error(`API Error: ${response.status} - ${errorText}`);
      }
      const generatedData = await response.json();
      setPropertyDetails({
        ...formData,
        generatedTitle: generatedData.title,
        enhancedDescription: generatedData.description,
        features: generatedData.features,
      });
    } catch (err: any) {
      console.error("⚠️ AI Call Failed:", err);
      if (err.message && (err.message.includes("500") || err.message.includes("API key"))) {
          setShowSystemCheck(true);
      } else { alert("שגיאה בחיבור לשרת ה-AI: " + err.message); }
    } finally { setIsLoading(false); }
  };

  const uploadFile = async (base64: string, path: string): Promise<string> => {
    if (!storage) throw new Error("Storage not initialized");
    try {
        const storageRef = ref(storage, path);
        const snapshot = await uploadString(storageRef, base64, 'data_url');
        return await getDownloadURL(snapshot.ref);
    } catch (error: any) {
        console.error("Upload error for path:", path, error);
        if (error.code === 'storage/unauthorized') {
            throw new Error("אין הרשאה להעלות תמונות. בדוק את ה-Rules ב-Storage.");
        } else if (error.code === 'storage/project-not-found') {
            throw new Error("פרויקט Firebase לא נמצא. וודא ש-projectId ו-storageBucket נכונים.");
        }
        throw error;
    }
  };

  const handleSaveAndPublish = async () => {
    if (!propertyDetails || !user) return;
    if (!db || !storage) { alert("שגיאת חיבור לשירותי Firebase."); return; }

    setIsSaving(true);
    try {
      const docRef = doc(collection(db, "landingPages"));
      const newId = docRef.id;
      const slug = slugify(propertyDetails.address);

      // 1. Upload Images
      let imageUrls: string[] = [];
      try {
          imageUrls = await Promise.all(
            propertyDetails.images.map((img, index) => 
                uploadFile(img, `properties/${newId}/image_${index}.jpg`)
            )
          );
      } catch (uploadErr: any) {
          throw new Error("כישלון בהעלאת תמונות: " + uploadErr.message);
      }

      // 2. Upload Logo
      let logoUrl = '';
      if (propertyDetails.logo) {
        try {
            logoUrl = await uploadFile(propertyDetails.logo, `properties/${newId}/logo.png`);
        } catch (logoErr) { console.warn("Logo upload failed, continuing without logo"); }
      }

      // 3. Save to Firestore
      const dataToSave: PropertyDetails = {
        ...propertyDetails,
        id: newId,
        slug: slug,
        userId: user.uid,
        userEmail: user.email || 'unknown',
        createdAt: Date.now(),
        images: imageUrls,
        logo: logoUrl,
      };

      await setDoc(docRef, dataToSave);

      const finalUrlPath = `/p/${slug}-${newId}`;
      const fullUrl = `${window.location.origin}${finalUrlPath}`;

      navigator.clipboard.writeText(fullUrl).then(() => {
        alert("הדף פורסם בהצלחה! הקישור הועתק.");
        router.push(finalUrlPath);
      }).catch(() => router.push(finalUrlPath));

    } catch (error: any) {
        console.error("Critical error during save:", error);
        alert(error.message || "אירעה שגיאה בשמירת הדף.");
        setIsSaving(false);
    }
  };

  const resetApp = () => setPropertyDetails(null);

  if (!isClient) return <div className="flex justify-center items-center min-h-screen bg-slate-900"><div className="animate-spin rounded-full h-32 w-32 border-b-2 border-brand-accent"></div></div>;

  if (initializationError || !auth) {
      return (
          <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4" dir="rtl">
              <div className="bg-slate-800/80 border border-slate-700 p-8 rounded-2xl max-w-2xl w-full text-center shadow-2xl">
                  <h1 className="text-3xl font-bold text-white mb-4">נדרשת הגדרת מפתחות</h1>
                  <p className="text-slate-300 mb-6 text-right">האפליקציה לא הצליחה להתחבר ל-Firebase. וודא שערכת את קובץ <code>lib/firebase.ts</code> ומילאת את <code>HARDCODED_CONFIG</code>.</p>
                  <button onClick={() => window.location.reload()} className="bg-brand-accent text-white px-6 py-3 rounded-xl font-bold w-full">רענן עמוד</button>
              </div>
          </div>
      );
  }

  return (
    <div className="min-h-screen relative bg-slate-900">
      {showSystemCheck && <SystemCheckModal onClose={() => setShowSystemCheck(false)} />}
      <div className="absolute top-0 left-0 right-0 p-4 z-50 flex justify-between items-start pointer-events-none">
          <div className="pointer-events-auto">
             <Auth user={user} isAdmin={isAdmin} onViewChange={(view) => { setCurrentView(view); resetApp(); }} currentView={currentView} />
          </div>
      </div>
      <div className="pt-16">
          {currentView === 'admin' && isAdmin ? (
              <AdminDashboard />
          ) : currentView === 'dashboard' && user ? (
              <UserDashboard userId={user.uid} onCreateNew={() => setCurrentView('create')} />
          ) : (
              propertyDetails ? (
                <LandingPage details={propertyDetails} isPreview={true} onReset={resetApp} onSave={handleSaveAndPublish} isSaving={isSaving} />
              ) : (
                <div className="relative">
                   {!user && (
                       <div className="absolute inset-0 z-40 bg-slate-900/80 backdrop-blur-sm flex flex-col items-center justify-center text-center p-4">
                           <h2 className="text-3xl font-bold text-white mb-4">ברוכים הבאים למחולל דפי הנחיתה</h2>
                           <p className="text-slate-300 mb-8 max-w-md">התחבר באמצעות חשבון Google כדי להתחיל.</p>
                       </div>
                   )}
                   <CreationForm onSubmit={handleFormSubmit} isLoading={isLoading} />
                </div>
              )
          )}
      </div>
      <div className="fixed bottom-2 left-2 z-50 opacity-30 hover:opacity-100"><button onClick={() => setShowSystemCheck(true)} className="text-[10px] text-slate-500 bg-slate-900/50 px-2 py-1 rounded border border-slate-700">System Check</button></div>
    </div>
  );
};

export default HomePage;

import React, { useEffect, useState } from 'react';
import { db } from '../lib/firebase';
import { collection, getDocs, query, where, orderBy } from 'firebase/firestore';
import type { PropertyDetails } from '../types';

interface UserDashboardProps {
    userId: string;
    onCreateNew: () => void;
}

export const UserDashboard: React.FC<UserDashboardProps> = ({ userId, onCreateNew }) => {
  const [myProperties, setMyProperties] = useState<PropertyDetails[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchMyProperties = async () => {
      if (!db) {
          setError("מסד הנתונים לא מחובר.");
          setLoading(false);
          return;
      }

      try {
        // Attempt query with ordering (requires composite index)
        const q = query(
            collection(db, 'landingPages'), 
            where('userId', '==', userId),
            orderBy('createdAt', 'desc')
        );
        const querySnapshot = await getDocs(q);
        const propsData = querySnapshot.docs.map(doc => ({ ...doc.data() as any, id: doc.id } as PropertyDetails));
        setMyProperties(propsData);
        setError(null);
      } catch (err: any) {
        console.error("Dashboard query error:", err);

        // If it's a missing index error, try fallback without ordering
        if (err.message && err.message.includes("index")) {
            console.warn("Firestore index missing. Falling back to unordered query.");
            try {
                const fallbackQ = query(
                    collection(db, 'landingPages'), 
                    where('userId', '==', userId)
                );
                const querySnapshot = await getDocs(fallbackQ);
                const propsData = querySnapshot.docs.map(doc => ({ ...doc.data() as any, id: doc.id } as PropertyDetails));
                setMyProperties(propsData);
                setError("שימו לב: חסר אינדקס ב-Firebase. הנכסים מוצגים ללא מיון תאריכים.");
            } catch (fallbackErr) {
                setError("שגיאה בטעינת הנכסים.");
            }
        } else {
            setError("אירעה שגיאה בטעינת הנכסים שלך.");
        }
      } finally {
        setLoading(false);
      }
    };

    if (userId) fetchMyProperties();
  }, [userId]);

  const copyToClipboard = (slug: string, id: string) => {
    const url = `${window.location.origin}/p/${slug}-${id}`;
    navigator.clipboard.writeText(url);
    alert('הקישור הועתק ללוח');
  };

  if (loading) return <div className="text-white text-center py-20"><div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-accent mx-auto"></div><p className="mt-4">טוען את הנכסים שלך...</p></div>;

  return (
    <div className="container mx-auto px-4 py-8 animate-fade-in">
      <div className="flex justify-between items-center mb-8 border-b border-slate-700 pb-4">
          <h1 className="text-3xl font-bold text-white">הנכסים שלי</h1>
          <button onClick={onCreateNew} className="bg-brand-accent hover:bg-brand-accentHover text-white px-6 py-2 rounded-xl font-bold shadow-lg transition-all">
              + צור דף חדש
          </button>
      </div>

      {error && (
          <div className="bg-orange-900/30 border border-orange-500/50 p-4 rounded-xl mb-6 text-orange-200 text-sm">
              <p className="font-bold mb-1">הודעת מערכת:</p>
              <p>{error}</p>
              {error.includes("אינדקס") && (
                  <p className="mt-2 text-xs opacity-80">בדוק את ה-Console בדפדפן (F12) כדי למצוא קישור ישיר ליצירת האינדקס ב-Firebase.</p>
              )}
          </div>
      )}

      {myProperties.length === 0 ? (
          <div className="text-center py-20 bg-slate-800/30 rounded-3xl border border-slate-700 border-dashed">
              <h3 className="text-xl text-slate-300 mb-4">עדיין לא יצרת דפי נחיתה</h3>
              <p className="text-slate-500 mb-6">כל דף שתיצור ותפרסם יופיע כאן לניהול מהיר.</p>
              <button onClick={onCreateNew} className="bg-slate-700 hover:bg-slate-600 text-white px-8 py-3 rounded-xl font-bold transition-all">צור את הדף הראשון שלך</button>
          </div>
      ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {myProperties.map((prop) => (
                  <div key={prop.id} className="bg-slate-800 border border-slate-700 rounded-2xl overflow-hidden hover:border-brand-accent/50 transition-all group">
                      <div className="h-48 overflow-hidden relative">
                          <img src={prop.images[0]} alt={prop.generatedTitle} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                          <div className="absolute top-2 right-2 bg-black/60 text-white text-xs px-2 py-1 rounded backdrop-blur-sm">
                              {prop.features.rooms ? `${prop.features.rooms} חדרים` : 'נכס'}
                          </div>
                      </div>
                      <div className="p-5">
                          <h3 className="text-white font-bold text-lg mb-2 line-clamp-1">{prop.generatedTitle}</h3>
                          <p className="text-slate-400 text-sm mb-4 truncate">{prop.address}</p>

                          <div className="flex gap-2 mt-4">
                              <a 
                                href={`/p/${prop.slug}-${prop.id}`} 
                                target="_blank"
                                className="flex-1 bg-slate-700 hover:bg-slate-600 text-white text-center py-2 rounded-lg text-sm font-medium transition-colors"
                              >
                                  צפה בדף
                              </a>
                              <button 
                                onClick={() => copyToClipboard(prop.slug || '', prop.id || '')}
                                className="bg-slate-700 hover:bg-brand-accent text-white p-2 rounded-lg transition-colors"
                                title="העתק קישור"
                              >
                                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>
                              </button>
                          </div>
                      </div>
                  </div>
              ))}
          </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { db } from '../lib/firebase';
import { collection, getDocs, query, where, orderBy } from 'firebase/firestore';
import type { PropertyDetails } from '../types';

interface UserDashboardProps {
    userId: string;
    onCreateNew: () => void;
}

export const UserDashboard: React.FC<UserDashboardProps> = ({ userId, onCreateNew }) => {
  const [myProperties, setMyProperties] = useState<PropertyDetails[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchMyProperties = async () => {
    if (!db) {
        setError("מסד הנתונים לא מחובר.");
        setLoading(false);
        return;
    }

    setLoading(true);
    console.log("Fetching properties for UID:", userId);

    try {
      // Step 1: Try the simplest query possible first (no ordering)
      // This rules out indexing issues.
      const simpleQuery = query(
          collection(db, 'landingPages'), 
          where('userId', '==', userId)
      );

      const querySnapshot = await getDocs(simpleQuery);
      console.log(`Found ${querySnapshot.size} documents for this user.`);

      let propsData = querySnapshot.docs.map(doc => ({ 
          ...doc.data() as any, 
          id: doc.id 
      } as PropertyDetails));

      // Step 2: Manually sort in memory instead of relying on Firestore Index
